'use strict';

/**
 * Bundles all built-in rules packs into a single JS file (builtin-packs.js).
 * The output assigns window.BC_BUILTIN_PACKS so the browser can load the data
 * via a plain <script> tag — no fetch() required, works on file:// too.
 */

const fs   = require('fs');
const path = require('path');

const ROOT    = path.resolve(__dirname, '..');
const RULEPACK_DIR = path.join(ROOT, 'rulepacks');
const OUT     = path.join(ROOT, 'builtin-packs.js');

const PACK_FILES = [
  'AC-rules-pack.json',
  'TYR-rules-pack.json',
  'TAU-rules-pack.json',
  'IK-rules-pack.json',
  'SM-BT-rules-pack.json',
  'CN-SM-BT-rules-pack.json',
  'SM-UM-rules-pack.json',
];

const packs = {};
for (const file of PACK_FILES) {
  const data = JSON.parse(fs.readFileSync(path.join(RULEPACK_DIR, file), 'utf8'));
  packs[data.id] = data;
  console.log(`Bundled: ${file} (id=${data.id})`);
}

const banner = `/* AUTO-GENERATED by tools/bundle-builtin-packs.js — do not edit manually */\n`;
const content = `${banner}window.BC_BUILTIN_PACKS = ${JSON.stringify(packs, null, 2)};\n`;

fs.writeFileSync(OUT, content, 'utf8');
console.log(`\nWrote ${OUT} (${(fs.statSync(OUT).size / 1024).toFixed(1)} KB)`);
